@app.route("/reset-mfa/confirm", methods=["GET", "POST"])
def confirm_reset_mfa():
    token = request.args.get("token") or (request.get_json(silent=True) or {}).get("token")
    if not token:
        return jsonify({"error": "token is required"}), 400

    db = get_db()
    row = db.execute(
        """
        SELECT t.*, u.email
        FROM mfa_reset_tokens t
        JOIN users u ON u.id = t.user_id
        WHERE t.token = ?
        """,
        (token,),
    ).fetchone()

    if not row:
        return jsonify({"error": "invalid token"}), 400

    if row["used"]:
        return jsonify({"error": "token already used"}), 400

    if parse_iso(row["expires_at"]) < now_utc():
        return jsonify({"error": "token expired"}), 400

    db.execute(
        "UPDATE users SET mfa_enabled = 0, mfa_secret = NULL WHERE id = ?",
        (row["user_id"],),
    )
    db.execute(
        "UPDATE mfa_reset_tokens SET used = 1 WHERE id = ?",
        (row["id"],),
    )
    db.commit()

    return jsonify({
        "message": "MFA has been reset. You can now log in with just your password.",
        "email": row["email"]
    }), 200


